// // This module implements a 2-to-1 multiplexer with B1 as the select input. When B1 is LOW (0), Y outputs A2; when B1 is HIGH (1), Y outputs A1.
module top_module(
    Y   ,
    A1  ,
    A2  ,
    B1  ,
    VPWR,
    VGND,
    VPB ,
    VNB
);output Y   ;
    input  A1  ;
    input  A2  ;
    input  B1  ;
    input  VPWR;
    input  VGND;
    input  VPB ;
    input  VNB ;

    wire select;
    assign select = B1;

    assign Y = (select == 1'b0) ? A1 : A2;

endmodule
